    setError('');
    setSuccess('');
    setUsername('');
    setPassword('');
    setEmail('');
    setName('');
  };

  const handleRoleSelect = (role: Role) => {
    setSelectedRole(role);
    setStep('LOGIN');
    resetForm();
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (selectedRole === 'TEACHER') {
      if (username === MOCK_TEACHER.username && password === MOCK_TEACHER.password) {
        onLoginSuccess(MOCK_TEACHER);
      } else {
        setError('Invalid teacher credentials.');
      }
    } else {
      const students = storageService.getAllStudents();
      const student = students.find(s => (s.username === username || s.email === username) && s.password === password);
      if (student) {
        onLoginSuccess(student);
      } else {
        setError('Invalid student credentials.');
      }
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

