import React, { useState, useEffect } from 'react';
import { Assessment, User, Submission } from '../../types';
import { Card } from '../UI/Card';
import { MCQSession } from '../Assessment/MCQSession';
import { storageService } from '../../services/storageService';

interface StudentDashboardProps {
  user: User;
  assessments: Assessment[];
}

export const StudentDashboard: React.FC<StudentDashboardProps> = ({ user, assessments }) => {
  const [activeAssessment, setActiveAssessment] = useState<Assessment | null>(null);
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchSubmissions();
  }, [user.id]);

  const fetchSubmissions = async () => {
    try {
      setLoading(true);
      const data = await storageService.getSubmissions(user.id);
      setSubmissions(data);
    } catch (err) {
      console.error("Error fetching submissions:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleComplete = async (submission: Submission) => {
    try {
      await storageService.saveSubmission(submission);
      await fetchSubmissions(); // Refresh list
    } catch (err) {
      console.error("Error saving submission:", err);
    }
  };

  const handleCancel = () => {
    setActiveAssessment(null);
  };

  if (activeAssessment) {
    return (
      <div className="py-8 px-4">
        <MCQSession 
          assessment={activeAssessment} 
          studentId={user.id} 
          onComplete={handleComplete} 
          onCancel={handleCancel}
        />
      </div>
    );
  }

  const practiceSets = assessments.filter(a => a.type === 'PRACTICE');
  const testSets = assessments.filter(a => a.type === 'TEST');

  return (
    <div className="max-w-6xl mx-auto py-10 px-4">
      <header className="mb-10">
        <h1 className="text-4xl font-extrabold text-gray-900 mb-2">Welcome back, {user.name}!</h1>
        <p className="text-lg text-gray-600">Choose your activity for today and continue learning.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-12">
        {/* Practice Card */}
        <Card className="hover:shadow-lg transition-shadow border-l-4 border-l-green-500">
          <div className="flex flex-col h-full">
            <div className="flex items-center gap-4 mb-4">
              <div className="bg-green-100 p-4 rounded-2xl">
                <i className="fa-solid fa-pen-nib text-green-600 text-3xl"></i>
              </div>
              <div>
                <h2 className="text-2xl font-bold text-gray-800">Practice Zone</h2>
                <p className="text-gray-500">Sharpen your skills with no pressure.</p>
              </div>
            </div>
            <div className="space-y-3 mb-6 flex-grow">
              {practiceSets.map(set => (
                <div key={set.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <span className="font-medium text-gray-700">{set.title}</span>
                  <button 
                    onClick={() => setActiveAssessment(set)}
                    className="text-green-600 font-bold hover:underline"
                  >
                    Start
                  </button>
                </div>
              ))}
            </div>
          </div>
        </Card>

        {/* Test Card */}
        <Card className="hover:shadow-lg transition-shadow border-l-4 border-l-indigo-500">
          <div className="flex flex-col h-full">
            <div className="flex items-center gap-4 mb-4">
              <div className="bg-indigo-100 p-4 rounded-2xl">
                <i className="fa-solid fa-stopwatch text-indigo-600 text-3xl"></i>
              </div>
              <div>
                <h2 className="text-2xl font-bold text-gray-800">Exam Center</h2>
                <p className="text-gray-500">Timed tests to evaluate your progress.</p>
              </div>
            </div>
            <div className="space-y-3 mb-6 flex-grow">
              {testSets.map(set => (
                <div key={set.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <span className="font-medium text-gray-700">{set.title}</span>
                  <button 
                    onClick={() => setActiveAssessment(set)}
                    className="text-indigo-600 font-bold hover:underline"
                  >
                    Take Test
                  </button>
                </div>
              ))}
            </div>
          </div>
        </Card>
      </div>

      <Card title="Recent Performance" icon="fa-chart-line">
        {loading ? (
           <div className="flex items-center gap-3 text-gray-400 py-4">
              <i className="fa-solid fa-circle-notch animate-spin"></i>
              <span>Loading results from cloud...</span>
           </div>
        ) : submissions.length === 0 ? (
          <p className="text-gray-400 italic py-4">No assessments attempted yet.</p>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="border-b border-gray-100">
                  <th className="py-3 font-semibold text-gray-600">Assessment</th>
                  <th className="py-3 font-semibold text-gray-600">Date</th>
                  <th className="py-3 font-semibold text-gray-600">Score</th>
                  <th className="py-3 font-semibold text-gray-600 text-right">Action</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {submissions.slice().reverse().map((sub, idx) => {
                  const assessment = assessments.find(a => a.id === sub.assessmentId);
                  return (
                    <tr key={idx} className="group">
                      <td className="py-4">
                        <span className="font-medium text-gray-800">{assessment?.title || 'Unknown'}</span>
                        <span className={`ml-2 px-2 py-0.5 rounded text-xs ${assessment?.type === 'TEST' ? 'bg-indigo-100 text-indigo-700' : 'bg-green-100 text-green-700'}`}>
                          {assessment?.type}
                        </span>
                      </td>
                      <td className="py-4 text-gray-500">{new Date(sub.completedAt).toLocaleDateString()}</td>
                      <td className="py-4">
                        <span className={`font-bold ${sub.score / sub.totalQuestions >= 0.7 ? 'text-green-600' : 'text-orange-500'}`}>
                          {sub.score} / {sub.totalQuestions}
                        </span>
                      </td>
                      <td className="py-4 text-right">
                        <button className="text-gray-400 group-hover:text-indigo-600">
                          <i className="fa-solid fa-chevron-right"></i>
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </Card>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Assessment, User, Submission } from '../../types';
import { Card } from '../UI/Card';
import { storageService } from '../../services/storageService';

interface TeacherDashboardProps {
  user: User;
  assessments: Assessment[];
}

export const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ assessments }) => {
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [students, setStudents] = useState<User[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true);
        const [allSubmissions, allStudents] = await Promise.all([
          storageService.getSubmissions(),
          storageService.getAllStudents()
        ]);
        setSubmissions(allSubmissions);
        setStudents(allStudents);
      } catch (err) {
        console.error("Error loading teacher data:", err);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  const getStudentSubmissions = (studentId: string) => {
    return submissions.filter(s => s.studentId === studentId);
  };

  const getAverageScore = (studentId: string) => {
    const subs = getStudentSubmissions(studentId);
    if (subs.length === 0) return 0;
    const total = subs.reduce((acc, curr) => acc + (curr.score / curr.totalQuestions), 0);
    return (total / subs.length) * 100;
  };

  if (loading) {
    return (
      <div className="max-w-7xl mx-auto py-20 px-4 text-center">
        <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
        <p className="text-gray-500 font-bold">Synchronizing Faculty Data...</p>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto py-10 px-4">
      <header className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-4">
        <div>
          <h1 className="text-4xl font-extrabold text-gray-900 mb-1">Teacher Dashboard</h1>
          <p className="text-lg text-gray-600">Monitoring Panday Classes excellence.</p>
        </div>
        <div className="flex gap-4">
          <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex items-center gap-3">
            <div className="p-2 bg-indigo-50 rounded-lg">
              <i className="fa-solid fa-users text-indigo-600"></i>
            </div>
            <div>
              <p className="text-xs text-gray-500 font-bold uppercase">Students</p>
              <p className="text-xl font-bold">{students.length}</p>
            </div>
          </div>
          <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex items-center gap-3">
            <div className="p-2 bg-green-50 rounded-lg">
              <i className="fa-solid fa-file-invoice text-green-600"></i>
            </div>
            <div>
              <p className="text-xs text-gray-500 font-bold uppercase">Submissions</p>
              <p className="text-xl font-bold">{submissions.length}</p>
            </div>
          </div>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Student List */}
        <div className="lg:col-span-1">
          <Card title="Students List" icon="fa-user-graduate">
            <div className="space-y-2">
              {students.map(student => {
                const avg = getAverageScore(student.id);
                const isActive = selectedStudent?.id === student.id;
                return (
                  <button
                    key={student.id}
                    onClick={() => setSelectedStudent(student)}
                    className={`w-full text-left p-4 rounded-xl transition-all border flex items-center gap-3 ${
                      isActive 
                        ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' 
                        : 'bg-gray-50 border-gray-100 text-gray-700 hover:bg-gray-100'
                    }`}
                  >
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold ${isActive ? 'bg-white text-indigo-600' : 'bg-indigo-100 text-indigo-700'}`}>
                      {student.name.charAt(0)}
                    </div>
                    <div className="flex-grow">
                      <p className="font-bold">{student.name}</p>
                      <p className={`text-xs ${isActive ? 'text-indigo-100' : 'text-gray-500'}`}>
                        {getStudentSubmissions(student.id).length} assessments completed
                      </p>
                    </div>
                    {avg > 0 && (
                      <div className={`text-xs font-black rounded px-2 py-1 ${isActive ? 'bg-indigo-500' : 'bg-white border'}`}>
                        {Math.round(avg)}%
                      </div>
                    )}
                  </button>
                );
              })}
            </div>
          </Card>
        </div>

        {/* Student Detail / Stats */}
        <div className="lg:col-span-2">
          {selectedStudent ? (
            <div className="space-y-6">
              <Card title={`${selectedStudent.name}'s Progress`} icon="fa-chart-column">
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="border-b border-gray-100">
                        <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Date</th>
                        <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Assessment</th>
                        <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Type</th>
                        <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Score</th>
                        <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Accuracy</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-50">
                      {getStudentSubmissions(selectedStudent.id).slice().reverse().map((sub, sidx) => {
                        const assessment = assessments.find(a => a.id === sub.assessmentId);
                        const accuracy = (sub.score / sub.totalQuestions) * 100;
                        return (
                          <tr key={sidx}>
                            <td className="py-4 text-sm text-gray-500">
                              {new Date(sub.completedAt).toLocaleDateString()}
                            </td>
                            <td className="py-4">
                              <span className="font-semibold text-gray-800">{assessment?.title}</span>
                            </td>
                            <td className="py-4">
                              <span className={`px-2 py-1 rounded text-[10px] font-black uppercase ${
                                assessment?.type === 'TEST' ? 'bg-indigo-100 text-indigo-700' : 'bg-green-100 text-green-700'
                              }`}>
                                {assessment?.type}
                              </span>
                            </td>
                            <td className="py-4">
                              <span className="font-bold text-gray-700">{sub.score} / {sub.totalQuestions}</span>
                            </td>
                            <td className="py-4">
                              <div className="w-full bg-gray-100 rounded-full h-1.5 max-w-[80px]">
                                <div 
                                  className={`h-full rounded-full ${accuracy >= 80 ? 'bg-green-500' : accuracy >= 50 ? 'bg-yellow-500' : 'bg-red-500'}`}
                                  style={{ width: `${accuracy}%` }}
                                />
                              </div>
                            </td>
                          </tr>
                        );
                      })}
                      {getStudentSubmissions(selectedStudent.id).length === 0 && (
                        <tr>
                          <td colSpan={5} className="py-10 text-center text-gray-400 italic">
                            No data available for this student yet.
                          </td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </Card>

              {/* Performance Summary Card */}
              {getStudentSubmissions(selectedStudent.id).length > 0 && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                   <Card className="bg-indigo-50 border-indigo-100">
                      <p className="text-indigo-600 text-xs font-bold uppercase mb-1">Global Average</p>
                      <p className="text-3xl font-black text-indigo-900">{Math.round(getAverageScore(selectedStudent.id))}%</p>
                   </Card>
                   <Card className="bg-green-50 border-green-100">
                      <p className="text-green-600 text-xs font-bold uppercase mb-1">Total Attempted</p>
                      <p className="text-3xl font-black text-green-900">{getStudentSubmissions(selectedStudent.id).length}</p>
                   </Card>
                </div>
              )}
            </div>
          ) : (
            <div className="h-full min-h-[400px] flex flex-col items-center justify-center bg-gray-50 border-2 border-dashed border-gray-200 rounded-2xl p-10 text-center">
              <i className="fa-solid fa-cloud-arrow-down text-gray-300 text-5xl mb-4"></i>
              <h3 className="text-xl font-bold text-gray-400">Select a student to view cloud-synced progress.</h3>
              <p className="text-gray-400 max-w-sm mt-2">All student records are securely retrieved from the Firebase Firestore database.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export type Role = 'TEACHER' | 'STUDENT';

export interface User {
  id: string;
  name: string;
  email: string;
  role: Role;
  password?: string;
  username?: string;
}

export interface MCQOption {
  id: string;
  text: string;
}

export interface Question {
  id: string;
  text: string;
  options: MCQOption[];
  correctOptionId: string;
  explanation?: string;
}

export type AssessmentType = 'PRACTICE' | 'TEST';
export type Subject = 'Mathematics' | 'Physics' | 'Chemistry';

export interface Assessment {
  id: string;
  title: string;
  type: AssessmentType;
  subject?: Subject;
  questions: Question[];
  durationMinutes?: number;
}

export interface Submission {
  id: string;
  studentId: string;
  assessmentId: string;
  score: number;
  totalQuestions: number;
  completedAt: string;
  responses: Record<string, string>; // questionId -> selectedOptionId
}

export interface AppState {
  currentUser: User | null;
  assessments: Assessment[];
  submissions: Submission[];
}

