import React, { useState } from 'react';
import { Assessment, Submission, Question } from '../../types';
import { Card } from '../UI/Card';
import { GoogleGenAI } from "@google/genai";

interface MCQSessionProps {
  assessment: Assessment;
  studentId: string;
  onComplete: (submission: Submission) => void;
  onCancel: () => void;
}

export const MCQSession: React.FC<MCQSessionProps> = ({ assessment, studentId, onComplete, onCancel }) => {
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [responses, setResponses] = useState<Record<string, string>>({});
  const [isFinished, setIsFinished] = useState(false);
  const [revealedAnswers, setRevealedAnswers] = useState<Record<string, boolean>>({});
  const [isReviewing, setIsReviewing] = useState(false);
  const [reviewIndex, setReviewIndex] = useState(0);
  const [aiExplanation, setAiExplanation] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  // Derived data
  const isPractice = assessment.type === 'PRACTICE';
  const currentQuestion = assessment.questions[currentQuestionIndex];
  const isLastQuestion = currentQuestionIndex === assessment.questions.length - 1;
  const hasSelected = !!responses[currentQuestion.id];
  const isRevealed = !!revealedAnswers[currentQuestion.id];

  const incorrectQuestions = assessment.questions.filter(q => responses[q.id] !== q.correctOptionId);
  const currentReviewQuestion = incorrectQuestions[reviewIndex];

  // AI Tutor Integration using Gemini 3 Pro for complex reasoning
  const handleAskGemini = async (question: Question) => {
    setIsAiLoading(true);
    setAiExplanation(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `You are an expert tutor for Panday Classes. 
      The student got this question wrong: "${question.text}"
      The correct answer is: "${question.options.find(o => o.id === question.correctOptionId)?.text}".
      The student chose: "${question.options.find(o => o.id === responses[question.id])?.text}".
      Provide a deep, reassuring, and logical explanation (max 100 words) of why the correct answer is right and why the student's choice was incorrect.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          thinkingConfig: { thinkingBudget: 2000 }
        }
      });
      setAiExplanation(response.text);
    } catch (err) {
      console.error("Gemini AI Error:", err);
      setAiExplanation("I'm sorry, I'm having trouble connecting to my knowledge base right now. Please try again later!");
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleSelectOption = (optionId: string) => {
    if (isRevealed) return; // Prevent changing after showing answer in practice
    setResponses(prev => ({
      ...prev,
      [currentQuestion.id]: optionId
    }));
  };

  const handleShowAnswer = () => {
    setRevealedAnswers(prev => ({ ...prev, [currentQuestion.id]: true }));
  };

  const calculateScore = () => {
    let score = 0;
    assessment.questions.forEach(q => {
      if (responses[q.id] === q.correctOptionId) {
        score++;
      }
    });
    return score;
  };

  const handleSubmit = () => {
    const finalScore = calculateScore();
    const submission: Submission = {
      id: Math.random().toString(36).substr(2, 9),
      studentId,
      assessmentId: assessment.id,
      score: finalScore,
      totalQuestions: assessment.questions.length,
      completedAt: new Date().toISOString(),
      responses
    };
    onComplete(submission);
    setIsFinished(true);
  };

  const getOptionStyles = (q: Question, optionId: string) => {
    const isSelected = responses[q.id] === optionId;
    const isCorrect = q.correctOptionId === optionId;
    const revealed = revealedAnswers[q.id] || isReviewing;

    if (!revealed) {
      return isSelected 
        ? 'border-indigo-600 bg-indigo-50 text-indigo-800' 
        : 'border-gray-100 hover:border-indigo-200 bg-gray-50 text-gray-700';
    }

    if (isCorrect) {
      return 'border-green-500 bg-green-50 text-green-800 font-bold';
    }

    if (isSelected && !isCorrect) {
      return 'border-red-500 bg-red-50 text-red-800 font-bold';
    }

    return 'border-gray-100 bg-gray-50 opacity-50 text-gray-400';
  };

  // --- REVIEW MODE UI ---
  if (isReviewing && currentReviewQuestion) {
    return (
      <div className="max-w-3xl mx-auto">
        <div className="flex justify-between items-center mb-6">
          <div>
            <span className="px-2 py-1 bg-red-100 text-red-700 text-[10px] font-black uppercase rounded mb-2 inline-block">Reviewing Mistakes</span>
            <h2 className="text-2xl font-bold text-gray-800">{assessment.title}</h2>
            <p className="text-gray-500">Mistake {reviewIndex + 1} of {incorrectQuestions.length}</p>
          </div>
          <button onClick={() => { setIsReviewing(false); setAiExplanation(null); }} className="text-gray-400 hover:text-indigo-600 font-bold flex items-center gap-2">
            Back <i className="fa-solid fa-arrow-turn-up"></i>
          </button>
        </div>

        <div className="bg-white rounded-xl shadow-md border border-gray-100 overflow-hidden mb-6">
           <div className="p-8">
            <p className="text-xl text-gray-800 font-medium mb-8">{currentReviewQuestion.text}</p>
            <div className="space-y-4">
              {currentReviewQuestion.options.map((option) => (
                <div key={option.id} className={`w-full p-4 rounded-xl border-2 flex items-center gap-4 ${getOptionStyles(currentReviewQuestion, option.id)}`}>
                  <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${
                    responses[currentReviewQuestion.id] === option.id ? 'border-red-500 bg-red-500' : 
                    currentReviewQuestion.correctOptionId === option.id ? 'border-green-500 bg-green-500' : 'border-gray-300'
                  }`}>
                    {(responses[currentReviewQuestion.id] === option.id || currentReviewQuestion.correctOptionId === option.id) && <div className="w-2 h-2 bg-white rounded-full" />}
                  </div>
                  <span>{option.text}</span>
                </div>
              ))}
            </div>

            <div className="mt-8 grid grid-cols-1 gap-4">
              {currentReviewQuestion.explanation && (
                <div className="p-4 bg-indigo-50 border-l-4 border-indigo-400 rounded">
                  <p className="text-sm font-bold text-indigo-700 uppercase mb-1">Standard Explanation</p>
                  <p className="text-indigo-900">{currentReviewQuestion.explanation}</p>
                </div>
              )}

              <div className="p-4 bg-violet-50 border-l-4 border-violet-400 rounded">
                <div className="flex justify-between items-center mb-2">
                  <p className="text-sm font-bold text-violet-700 uppercase">Gemini AI Tutor</p>
                  {!aiExplanation && !isAiLoading && (
                    <button 
                      onClick={() => handleAskGemini(currentReviewQuestion)}
                      className="text-[10px] bg-violet-600 text-white px-3 py-1 rounded-full hover:bg-violet-700 transition-colors"
                    >
                      Ask AI for help
                    </button>
                  )}
                </div>
                {isAiLoading ? (
                  <div className="flex items-center gap-2 text-violet-600 animate-pulse">
                    <i className="fa-solid fa-sparkles"></i>
                    <span className="text-sm font-bold">Gemini is thinking...</span>
                  </div>
                ) : aiExplanation ? (
                  <p className="text-violet-900 text-sm italic leading-relaxed">"{aiExplanation}"</p>
                ) : (
                  <p className="text-violet-400 text-sm">Need a deeper explanation? Ask our AI tutor.</p>
                )}
              </div>
            </div>
          </div>
          <div className="p-6 bg-gray-50 border-t border-gray-100 flex justify-between">
            <button
              disabled={reviewIndex === 0}
              onClick={() => { setReviewIndex(prev => prev - 1); setAiExplanation(null); }}
              className="px-6 py-2 font-semibold text-gray-600 hover:text-indigo-600 disabled:opacity-30"
            >
              <i className="fa-solid fa-arrow-left mr-2"></i> Previous
            </button>
            <button
              onClick={() => {
                if (reviewIndex === incorrectQuestions.length - 1) {
                  setIsReviewing(false);
                } else {
                  setReviewIndex(prev => prev + 1);
                  setAiExplanation(null);
                }
              }}
              className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-bold shadow-lg shadow-indigo-200"
            >
              {reviewIndex === incorrectQuestions.length - 1 ? 'Done Reviewing' : 'Next Mistake'}
            </button>
          </div>
        </div>
      </div>
    );
  }

  // --- FINISHED UI ---
  if (isFinished) {
    const score = calculateScore();
    const hasMistakes = incorrectQuestions.length > 0;
    return (
      <Card className="max-w-2xl mx-auto text-center" title="Assessment Completed">
        <div className="py-10">
          <div className="text-6xl mb-4">
            {score / assessment.questions.length >= 0.7 ? '🎉' : '📚'}
          </div>
          <h2 className="text-3xl font-bold text-gray-800 mb-2">Well Done!</h2>
          <p className="text-gray-600 mb-6">You've completed the {assessment.title}</p>
          <div className="bg-indigo-50 rounded-lg p-6 mb-8 inline-block">
            <span className="block text-sm text-indigo-600 font-semibold uppercase tracking-wider">Your Score</span>
            <span className="text-5xl font-black text-indigo-800">{score} / {assessment.questions.length}</span>
          </div>
          <div className="flex flex-col gap-3 max-w-xs mx-auto">
            {hasMistakes && (
              <button 
                onClick={() => setIsReviewing(true)}
                className="w-full bg-orange-500 hover:bg-orange-600 text-white font-bold py-3 px-6 rounded-lg transition-colors flex items-center justify-center gap-2"
              >
                <i className="fa-solid fa-magnifying-glass"></i> Review Mistakes
              </button>
            )}
            <button 
              onClick={onCancel}
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 px-6 rounded-lg transition-colors"
            >
              Return to Dashboard
            </button>
          </div>
        </div>
      </Card>
    );
  }

  // --- ACTIVE SESSION UI ---
  return (
    <div className="max-w-3xl mx-auto">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">{assessment.title}</h2>
          <p className="text-gray-500">Question {currentQuestionIndex + 1} of {assessment.questions.length}</p>
        </div>
        <button onClick={onCancel} className="text-gray-400 hover:text-red-500">
          <i className="fa-solid fa-xmark text-2xl"></i>
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-md border border-gray-100 overflow-hidden">
        <div className="w-full h-2 bg-gray-100">
          <div 
            className="h-full bg-indigo-600 transition-all duration-300"
            style={{ width: `${((currentQuestionIndex + 1) / assessment.questions.length) * 100}%` }}
          />
        </div>

        <div className="p-8">
          <p className="text-xl text-gray-800 font-medium mb-8">{currentQuestion.text}</p>
          <div className="space-y-4">
            {currentQuestion.options.map((option) => (
              <button
                key={option.id}
                disabled={isRevealed}
                onClick={() => handleSelectOption(option.id)}
                className={`w-full text-left p-4 rounded-xl border-2 transition-all flex items-center gap-4 ${getOptionStyles(currentQuestion, option.id)}`}
              >
                <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${
                  responses[currentQuestion.id] === option.id ? (isRevealed && currentQuestion.correctOptionId !== option.id ? 'border-red-500 bg-red-500' : 'border-indigo-600 bg-indigo-600') : 
                  (isRevealed && currentQuestion.correctOptionId === option.id ? 'border-green-500 bg-green-500' : 'border-gray-300')
                }`}>
                  {(responses[currentQuestion.id] === option.id || (isRevealed && currentQuestion.correctOptionId === option.id)) && <div className="w-2 h-2 bg-white rounded-full" />}
                </div>
                <span className="text-lg">{option.text}</span>
              </button>
            ))}
          </div>

          {isRevealed && currentQuestion.explanation && (
            <div className="mt-8 p-4 bg-indigo-50 border-l-4 border-indigo-400 rounded animate-in fade-in slide-in-from-top-2 duration-300">
              <p className="text-sm font-bold text-indigo-700 uppercase mb-1">Explanation</p>
              <p className="text-indigo-900">{currentQuestion.explanation}</p>
            </div>
          )}
        </div>

        <div className="p-6 bg-gray-50 border-t border-gray-100 flex items-center justify-between">
          <button
            disabled={currentQuestionIndex === 0}
            onClick={() => {
              setCurrentQuestionIndex(prev => prev - 1);
            }}
            className="px-4 py-2 font-semibold text-gray-600 hover:text-indigo-600 disabled:opacity-30"
          >
            <i className="fa-solid fa-arrow-left mr-2"></i> Previous
          </button>

          <div className="flex items-center gap-4">
            {isPractice && !isRevealed && (
              <button
                disabled={!hasSelected}
                onClick={handleShowAnswer}
                className="px-4 py-2 text-indigo-600 font-bold hover:bg-indigo-100 rounded-lg disabled:opacity-30 transition-colors flex items-center gap-2"
              >
                <i className="fa-solid fa-eye"></i> Show Answer
              </button>
            )}

            {isLastQuestion ? (
              <button
                disabled={!hasSelected}
                onClick={handleSubmit}
                className="px-8 py-3 bg-green-600 hover:bg-green-700 text-white rounded-lg font-bold shadow-lg shadow-green-200 transition-transform active:scale-95 disabled:opacity-50"
              >
                Finish & Submit
              </button>
            ) : (
              <button
                disabled={!hasSelected}
                onClick={() => {
                  setCurrentQuestionIndex(prev => prev + 1);
                }}
                className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-bold shadow-lg shadow-indigo-200 transition-transform active:scale-95 disabled:opacity-50"
              >
                Next <i className="fa-solid fa-arrow-right ml-2"></i>
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Assessment, User, Submission, Subject, AssessmentType } from '../../types';
import { Card } from '../UI/Card';
import { MCQSession } from '../Assessment/MCQSession';
import { storageService } from '../../services/storageService';

interface StudentDashboardProps {
  user: User;
  assessments: Assessment[];
}

type ViewState = 'DASHBOARD' | 'SUBJECT_PICKER' | 'SET_PICKER';

export const StudentDashboard: React.FC<StudentDashboardProps> = ({ user, assessments }) => {
  const [activeAssessment, setActiveAssessment] = useState<Assessment | null>(null);
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [loading, setLoading] = useState(true);

  // Navigation states
  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [selectedSubject, setSelectedSubject] = useState<Subject | null>(null);
  const [sessionMode, setSessionMode] = useState<AssessmentType>('PRACTICE');

  useEffect(() => {
    fetchSubmissions();
  }, [user.id]);

  const fetchSubmissions = async () => {
    try {
      setLoading(true);
      const data = await storageService.getSubmissions(user.id);
      setSubmissions(data);
    } catch (err) {
      console.error("Error fetching submissions:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleComplete = async (submission: Submission) => {
    try {
      await storageService.saveSubmission(submission);
      await fetchSubmissions(); 
      setActiveAssessment(null);
      setCurrentView('DASHBOARD');
    } catch (err) {
      console.error("Error saving submission:", err);
    }
  };

  const handleCancel = () => {
    setActiveAssessment(null);
  };

  const startSession = (mode: AssessmentType) => {
    setSessionMode(mode);
    setCurrentView('SUBJECT_PICKER');
  };

  // Content rendering logic
  if (activeAssessment) {
    return (
      <div className="py-8 px-4">
        <MCQSession 
          assessment={activeAssessment} 
          studentId={user.id} 
          onComplete={handleComplete} 
          onCancel={handleCancel}
        />
      </div>
    );
  }

  // --- Subject Selection View (Shared for Practice & Test) ---
  if (currentView === 'SUBJECT_PICKER') {
    const subjects: { name: Subject; icon: string; color: string; desc: string }[] = [
      { name: 'Mathematics', icon: 'fa-calculator', color: 'from-blue-500 to-indigo-600', desc: 'Algebra, Geometry, and Calculus.' },
      { name: 'Physics', icon: 'fa-bolt', color: 'from-orange-400 to-red-500', desc: 'Mechanics, Optics, and Electricity.' },
      { name: 'Chemistry', icon: 'fa-flask-vial', color: 'from-emerald-400 to-teal-600', desc: 'Elements, Reactions, and Bonding.' }
    ];

    return (
      <div className="max-w-6xl mx-auto py-10 px-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
        <button 
          onClick={() => setCurrentView('DASHBOARD')}
          className="flex items-center gap-2 text-indigo-600 font-bold mb-8 hover:translate-x-[-4px] transition-transform"
        >
          <i className="fa-solid fa-arrow-left"></i> Back to Dashboard
        </button>
        <div className="mb-8">
          <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border mb-2 inline-block ${sessionMode === 'TEST' ? 'bg-indigo-50 text-indigo-600 border-indigo-100' : 'bg-emerald-50 text-emerald-600 border-emerald-100'}`}>
            {sessionMode === 'TEST' ? 'Exam Center' : 'Practice Zone'}
          </span>
          <h2 className="text-3xl font-black text-gray-900">Choose a Subject</h2>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {subjects.map(subject => (
            <button
              key={subject.name}
              onClick={() => {
                setSelectedSubject(subject.name);
                setCurrentView('SET_PICKER');
              }}
              className="group relative h-64 overflow-hidden rounded-3xl shadow-xl transition-all hover:scale-[1.02] hover:shadow-2xl active:scale-95"
            >
              <div className={`absolute inset-0 bg-gradient-to-br ${subject.color} opacity-90`}></div>
              <div className="absolute inset-0 flex flex-col items-center justify-center p-6 text-white z-10">
                <i className={`fa-solid ${subject.icon} text-6xl mb-4 group-hover:scale-110 transition-transform text-white/90`}></i>
                <h3 className="text-2xl font-black mb-2">{subject.name}</h3>
                <p className="text-sm opacity-80 text-center font-medium">{subject.desc}</p>
              </div>
              <div className="absolute bottom-0 left-0 right-0 h-1 bg-white opacity-20"></div>
            </button>
          ))}
        </div>
      </div>
    );
  }

  // --- Set Selection View (Shared for Practice & Test) ---
  if (currentView === 'SET_PICKER' && selectedSubject) {
    const sets = assessments.filter(a => a.type === sessionMode && a.subject === selectedSubject);

    return (
      <div className="max-w-4xl mx-auto py-10 px-4 animate-in fade-in slide-in-from-right-4 duration-500">
        <div className="flex items-center justify-between mb-8">
          <button 
            onClick={() => setCurrentView('SUBJECT_PICKER')}
            className="flex items-center gap-2 text-indigo-600 font-bold hover:translate-x-[-4px] transition-transform"
          >
            <i className="fa-solid fa-arrow-left"></i> Back to Subjects
          </button>
          <div className="flex items-center gap-3">
             <span className={`px-4 py-1.5 rounded-full font-black text-xs uppercase tracking-widest border ${sessionMode === 'TEST' ? 'bg-indigo-50 text-indigo-700 border-indigo-100' : 'bg-emerald-50 text-emerald-700 border-emerald-100'}`}>
              {sessionMode} MODE
            </span>
            <span className="px-4 py-1.5 bg-gray-100 text-gray-700 rounded-full font-black text-xs uppercase tracking-widest border border-gray-200">
              {selectedSubject}
            </span>
          </div>
        </div>

        <h2 className="text-3xl font-black text-gray-900 mb-6">Available {sessionMode === 'TEST' ? 'Exam' : 'Practice'} Sets</h2>

        {sets.length === 0 ? (
          <div className="bg-white p-12 rounded-3xl border-2 border-dashed border-gray-200 text-center">
            <i className={`fa-solid ${sessionMode === 'TEST' ? 'fa-calendar-check' : 'fa-hourglass-start'} text-gray-300 text-5xl mb-4`}></i>
            <p className="text-gray-400 font-bold text-xl">No {sessionMode.toLowerCase()} sets currently available for {selectedSubject}.</p>
            <p className="text-gray-400 text-sm mt-2">Check back later or try another subject!</p>
          </div>
        ) : (
          <div className="space-y-4">
            {sets.map((set, idx) => (
              <button
                key={set.id}
                onClick={() => setActiveAssessment(set)}
                className={`w-full bg-white p-6 rounded-2xl border-2 border-gray-100 flex items-center justify-between group transition-all shadow-sm hover:shadow-md ${sessionMode === 'TEST' ? 'hover:border-indigo-600' : 'hover:border-emerald-600'}`}
              >
                <div className="flex items-center gap-4">
                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-black text-lg ${sessionMode === 'TEST' ? 'bg-indigo-50 text-indigo-600' : 'bg-emerald-50 text-emerald-600'}`}>
                    {idx + 1}
                  </div>
                  <div className="text-left">
                    <h4 className={`font-bold text-gray-800 text-lg transition-colors ${sessionMode === 'TEST' ? 'group-hover:text-indigo-600' : 'group-hover:text-emerald-600'}`}>{set.title}</h4>
                    <div className="flex items-center gap-3 mt-1">
                      <span className="text-xs text-gray-400 font-medium"><i className="fa-solid fa-list-check mr-1"></i> {set.questions.length} Questions</span>
                      {set.durationMinutes && (
                        <span className="text-xs text-gray-400 font-medium"><i className="fa-solid fa-clock mr-1"></i> {set.durationMinutes} Mins</span>
                      )}
                    </div>
                  </div>
                </div>
                <div className={`flex items-center gap-2 font-black uppercase text-xs ${sessionMode === 'TEST' ? 'text-indigo-600' : 'text-emerald-600'}`}>
                  {sessionMode === 'TEST' ? 'Attempt' : 'Start'} <i className="fa-solid fa-circle-play text-xl"></i>
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
    );
  }

  // --- Main Dashboard View ---
  return (
    <div className="max-w-6xl mx-auto py-10 px-4">
      <header className="mb-10 flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-extrabold text-gray-900 mb-2">Hello, {user.name}! 👋</h1>
          <p className="text-lg text-gray-600">Your roadmap to academic excellence starts here.</p>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-12">
        {/* Practice Card */}
        <Card className="!p-0 overflow-hidden group shadow-xl hover:shadow-2xl transition-all duration-300">
          <div className="p-8">
            <div className="flex items-center gap-4 mb-6">
              <div className="bg-emerald-100 p-4 rounded-2xl group-hover:bg-emerald-500 group-hover:text-white transition-all">
                <i className="fa-solid fa-graduation-cap text-3xl"></i>
              </div>
              <div>
                <h2 className="text-2xl font-black text-gray-800">Practice Zone</h2>
                <p className="text-gray-500">Adaptive learning for core subjects.</p>
              </div>
            </div>
            <p className="text-gray-600 mb-8 leading-relaxed">
              Master complex concepts through categorized practice sets in Mathematics, Physics, and Chemistry. Immediate feedback included.
            </p>
            <button 
              onClick={() => startSession('PRACTICE')}
              className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white font-black rounded-2xl shadow-lg shadow-emerald-100 flex items-center justify-center gap-3 transition-all"
            >
              Start Practice Session <i className="fa-solid fa-arrow-right"></i>
            </button>
          </div>
          <div className="bg-emerald-50 py-3 px-8 border-t border-emerald-100 flex justify-between text-xs font-bold text-emerald-700">
            <span>3 SUBJECTS AVAILABLE</span>
            <span>UNLIMITED ATTEMPTS</span>
          </div>
        </Card>

        {/* Test Card (Newly Styled to match Practice Zone) */}
        <Card className="!p-0 overflow-hidden group shadow-xl hover:shadow-2xl transition-all duration-300">
          <div className="p-8">
            <div className="flex items-center gap-4 mb-6">
              <div className="bg-indigo-100 p-4 rounded-2xl group-hover:bg-indigo-500 group-hover:text-white transition-all">
                <i className="fa-solid fa-stopwatch text-3xl"></i>
              </div>
              <div>
                <h2 className="text-2xl font-black text-gray-800">Test Center</h2>
                <p className="text-gray-500">Simulate real exam conditions.</p>
              </div>
            </div>
            <p className="text-gray-600 mb-8 leading-relaxed">
              Assess your preparation with timed unit tests and full-length mock exams. Get detailed proctored results and performance metrics.
            </p>
            <button 
              onClick={() => startSession('TEST')}
              className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-2xl shadow-lg shadow-indigo-100 flex items-center justify-center gap-3 transition-all"
            >
              Start Exam Session <i className="fa-solid fa-arrow-right"></i>
            </button>
          </div>
          <div className="bg-indigo-50 py-3 px-8 border-t border-indigo-100 flex justify-between text-xs font-bold text-indigo-700">
            <span>TIMED ASSESSMENT</span>
            <span>PROCTORED RESULTS</span>
          </div>
        </Card>
      </div>

      <Card title="Cloud Performance Analytics" icon="fa-chart-pie">
        {loading ? (
           <div className="flex flex-col items-center justify-center py-12 text-indigo-300">
              <i className="fa-solid fa-circle-notch animate-spin text-4xl mb-4"></i>
              <span className="font-bold uppercase tracking-widest text-xs">Syncing with server...</span>
           </div>
        ) : submissions.length === 0 ? (
          <div className="py-12 text-center">
            <i className="fa-solid fa-file-circle-question text-gray-200 text-6xl mb-4"></i>
            <p className="text-gray-400 font-bold">No activity history yet. Start a session to see analytics.</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="border-b border-gray-100">
                  <th className="py-4 font-black text-gray-400 uppercase text-[10px] tracking-widest">Assessment Details</th>
                  <th className="py-4 font-black text-gray-400 uppercase text-[10px] tracking-widest text-center">Date</th>
                  <th className="py-4 font-black text-gray-400 uppercase text-[10px] tracking-widest text-center">Score</th>
                  <th className="py-4 font-black text-gray-400 uppercase text-[10px] tracking-widest text-right">Progress</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {submissions.slice().reverse().map((sub, idx) => {
                  const assessment = assessments.find(a => a.id === sub.assessmentId);
                  const percentage = (sub.score / sub.totalQuestions) * 100;
                  return (
                    <tr key={idx} className="group hover:bg-gray-50/50 transition-colors">
                      <td className="py-5">
                        <div className="flex flex-col">
                          <span className="font-bold text-gray-800">{assessment?.title || 'Archive Set'}</span>
                          <span className={`w-fit mt-1 px-2 py-0.5 rounded text-[8px] font-black uppercase ${assessment?.type === 'TEST' ? 'bg-indigo-100 text-indigo-700' : 'bg-emerald-100 text-emerald-700'}`}>
                            {assessment?.subject || 'General'} • {assessment?.type}
                          </span>
                        </div>
                      </td>
                      <td className="py-5 text-center text-sm font-medium text-gray-500">
                        {new Date(sub.completedAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                      </td>
                      <td className="py-5 text-center">
                        <span className={`px-3 py-1 rounded-full font-black text-sm ${percentage >= 70 ? 'bg-emerald-50 text-emerald-600' : 'bg-orange-50 text-orange-600'}`}>
                          {sub.score} / {sub.totalQuestions}
                        </span>
                      </td>
                      <td className="py-5 text-right">
                         <div className="inline-flex items-center gap-3">
                            <div className="w-24 h-1.5 bg-gray-100 rounded-full overflow-hidden hidden sm:block">
                               <div className={`h-full transition-all duration-1000 ${percentage >= 70 ? 'bg-emerald-500' : 'bg-orange-400'}`} style={{ width: `${percentage}%` }}></div>
                            </div>
                            <span className="font-black text-gray-900 text-xs w-8">{Math.round(percentage)}%</span>
                         </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </Card>
    </div>
  );
};

