import React, { useState } from 'react';
import { Assessment, Submission, Question } from '../../types';
import { Card } from '../UI/Card';
import { GoogleGenAI } from "@google/genai";

interface MCQSessionProps {
  assessment: Assessment;
  studentId: string;
  onComplete: (submission: Submission) => void;
  onCancel: () => void;
}

export const MCQSession: React.FC<MCQSessionProps> = ({ assessment, studentId, onComplete, onCancel }) => {
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [responses, setResponses] = useState<Record<string, string>>({});
  const [isFinished, setIsFinished] = useState(false);
  const [revealedAnswers, setRevealedAnswers] = useState<Record<string, boolean>>({});
  const [isReviewing, setIsReviewing] = useState(false);
  const [reviewIndex, setReviewIndex] = useState(0);
  const [aiExplanation, setAiExplanation] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  // Derived data
  const isPractice = assessment.type === 'PRACTICE';
  const currentQuestion = assessment.questions[currentQuestionIndex];
  const isLastQuestion = currentQuestionIndex === assessment.questions.length - 1;
  const hasSelected = !!responses[currentQuestion.id];
  const isRevealed = !!revealedAnswers[currentQuestion.id];

  const incorrectQuestions = assessment.questions.filter(q => responses[q.id] !== q.correctOptionId);
  const currentReviewQuestion = incorrectQuestions[reviewIndex];

  // AI Tutor Integration using Gemini 3 Pro for complex reasoning
  const handleAskGemini = async (question: Question) => {
    setIsAiLoading(true);
    setAiExplanation(null);
    try {
      // Create a new instance right before the call to ensure up-to-date API key
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `You are an expert tutor for Panday Classes. 
      The student got this question wrong: "${question.text}"
      The correct answer is: "${question.options.find(o => o.id === question.correctOptionId)?.text}".
      The student chose: "${question.options.find(o => o.id === responses[question.id])?.text}".
      Provide a deep, reassuring, and logical explanation (max 100 words) of why the correct answer is right and why the student's choice was incorrect.`;

      // Use generateContent with both model name and prompt
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          // Guidelines: Always set maxOutputTokens and thinkingBudget together
          maxOutputTokens: 4096,
          thinkingConfig: { thinkingBudget: 2000 }
        }
      });
      // Access the .text property directly (not a method)
      setAiExplanation(response.text ?? "I'm sorry, I couldn't generate an explanation at this moment.");
    } catch (err) {
      console.error("Gemini AI Error:", err);
      setAiExplanation("I'm sorry, I'm having trouble connecting to my knowledge base right now. Please try again later!");
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleSelectOption = (optionId: string) => {
    if (isRevealed) return; // Prevent changing after showing answer in practice
    setResponses(prev => ({
      ...prev,
      [currentQuestion.id]: optionId
    }));
  };

  const handleShowAnswer = () => {
    setRevealedAnswers(prev => ({ ...prev, [currentQuestion.id]: true }));
  };

  const calculateScore = () => {
    let score = 0;
    assessment.questions.forEach(q => {
      if (responses[q.id] === q.correctOptionId) {
        score++;
      }
    });
    return score;
  };

  const handleSubmit = () => {
    const finalScore = calculateScore();
    const submission: Submission = {
      id: Math.random().toString(36).substr(2, 9),
      studentId,
      assessmentId: assessment.id,
      score: finalScore,
      totalQuestions: assessment.questions.length,
      completedAt: new Date().toISOString(),
      responses
    };
    onComplete(submission);
    setIsFinished(true);
  };

  const getOptionStyles = (q: Question, optionId: string) => {
    const isSelected = responses[q.id] === optionId;
    const isCorrect = q.correctOptionId === optionId;
    const revealed = revealedAnswers[q.id] || isReviewing;

    if (!revealed) {
      return isSelected 
        ? 'border-indigo-600 bg-indigo-50 text-indigo-800' 
        : 'border-gray-100 hover:border-indigo-200 bg-gray-50 text-gray-700';
    }

    if (isCorrect) {
      return 'border-green-500 bg-green-50 text-green-800 font-bold';
    }

    if (isSelected && !isCorrect) {
      return 'border-red-500 bg-red-50 text-red-800 font-bold';
    }

    return 'border-gray-100 bg-gray-50 opacity-50 text-gray-400';
  };

  // --- REVIEW MODE UI ---
  if (isReviewing && currentReviewQuestion) {
    return (
      <div className="max-w-3xl mx-auto">
        <div className="flex justify-between items-center mb-6">
          <div>
            <span className="px-2 py-1 bg-red-100 text-red-700 text-[10px] font-black uppercase rounded mb-2 inline-block">Reviewing Mistakes</span>
            <h2 className="text-2xl font-bold text-gray-800">{assessment.title}</h2>
            <p className="text-gray-500">Mistake {reviewIndex + 1} of {incorrectQuestions.length}</p>
          </div>
          <button onClick={() => { setIsReviewing(false); setAiExplanation(null); }} className="text-gray-400 hover:text-indigo-600 font-bold flex items-center gap-2">
            Back <i className="fa-solid fa-arrow-turn-up"></i>
          </button>
        </div>

        <div className="bg-white rounded-xl shadow-md border border-gray-100 overflow-hidden mb-6">
           <div className="p-8">
            <p className="text-xl text-gray-800 font-medium mb-4">{currentReviewQuestion.text}</p>

            {currentReviewQuestion.imageUrl && (
              <div className="mb-8 p-4 bg-white border border-gray-100 rounded-xl shadow-sm flex justify-center">
                <img 
                  src={currentReviewQuestion.imageUrl} 
                  alt="Question Diagram" 
                  className="max-h-48 object-contain"
                />
              </div>
            )}

            <div className="space-y-4">
              {currentReviewQuestion.options.map((option) => (
                <div key={option.id} className={`w-full p-4 rounded-xl border-2 flex items-center gap-4 ${getOptionStyles(currentReviewQuestion, option.id)}`}>
                  <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${
                    responses[currentReviewQuestion.id] === option.id ? 'border-red-500 bg-red-500' : 
                    currentReviewQuestion.correctOptionId === option.id ? 'border-green-500 bg-green-500' : 'border-gray-300'
                  }`}>
                    {(responses[currentReviewQuestion.id] === option.id || currentReviewQuestion.correctOptionId === option.id) && <div className="w-2 h-2 bg-white rounded-full" />}
                  </div>
                  <span>{option.text}</span>
                </div>
              ))}
            </div>

            <div className="mt-8 grid grid-cols-1 gap-4">
              {currentReviewQuestion.explanation && (
                <div className="p-4 bg-indigo-50 border-l-4 border-indigo-400 rounded">
                  <p className="text-sm font-bold text-indigo-700 uppercase mb-1">Standard Explanation</p>
                  <p className="text-indigo-900">{currentReviewQuestion.explanation}</p>
                </div>
              )}

              <div className="p-4 bg-violet-50 border-l-4 border-violet-400 rounded">
                <div className="flex justify-between items-center mb-2">
                  <p className="text-sm font-bold text-violet-700 uppercase">Gemini AI Tutor</p>
                  {!aiExplanation && !isAiLoading && (
                    <button 
                      onClick={() => handleAskGemini(currentReviewQuestion)}
                      className="text-[10px] bg-violet-600 text-white px-3 py-1 rounded-full hover:bg-violet-700 transition-colors"
                    >
                      Ask AI for help
                    </button>
                  )}
                </div>
                {isAiLoading ? (
                  <div className="flex items-center gap-2 text-violet-600 animate-pulse">
                    <i className="fa-solid fa-sparkles"></i>
                    <span className="text-sm font-bold">Gemini is thinking...</span>
                  </div>
                ) : aiExplanation ? (
                  <p className="text-violet-900 text-sm italic leading-relaxed">"{aiExplanation}"</p>
                ) : (
                  <p className="text-violet-400 text-sm">Need a deeper explanation? Ask our AI tutor.</p>
                )}
              </div>
            </div>
          </div>
          <div className="p-6 bg-gray-50 border-t border-gray-100 flex justify-between">
            <button
              disabled={reviewIndex === 0}
              onClick={() => { setReviewIndex(prev => prev - 1); setAiExplanation(null); }}
              className="px-6 py-2 font-semibold text-gray-600 hover:text-indigo-600 disabled:opacity-30"
            >
              <i className="fa-solid fa-arrow-left mr-2"></i> Previous
            </button>
            <button
              onClick={() => {
                if (reviewIndex === incorrectQuestions.length - 1) {
                  setIsReviewing(false);
                } else {
                  setReviewIndex(prev => prev + 1);
                  setAiExplanation(null);
                }
              }}
              className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-bold shadow-lg shadow-indigo-200"
            >
              {reviewIndex === incorrectQuestions.length - 1 ? 'Done Reviewing' : 'Next Mistake'}
            </button>
          </div>
        </div>
      </div>
    );
  }

  // --- FINISHED UI ---
  if (isFinished) {
    const score = calculateScore();
    const hasMistakes = incorrectQuestions.length > 0;
    return (
      <Card className="max-w-2xl mx-auto text-center" title="Assessment Completed">
        <div className="py-10">
          <div className="text-6xl mb-4">
            {score / assessment.questions.length >= 0.7 ? '🎉' : '📚'}
          </div>
          <h2 className="text-3xl font-bold text-gray-800 mb-2">Well Done!</h2>
          <p className="text-gray-600 mb-6">You've completed the {assessment.title}</p>
          <div className="bg-indigo-50 rounded-lg p-6 mb-8 inline-block">
            <span className="block text-sm text-indigo-600 font-semibold uppercase tracking-wider">Your Score</span>
            <span className="text-5xl font-black text-indigo-800">{score} / {assessment.questions.length}</span>
          </div>
          <div className="flex flex-col gap-3 max-w-xs mx-auto">
            {hasMistakes && (
              <button 
                onClick={() => setIsReviewing(true)}
                className="w-full bg-orange-500 hover:bg-orange-600 text-white font-bold py-3 px-6 rounded-lg transition-colors flex items-center justify-center gap-2"
              >
                <i className="fa-solid fa-magnifying-glass"></i> Review Mistakes
              </button>
            )}
            <button 
              onClick={onCancel}
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 px-6 rounded-lg transition-colors"
            >
              Return to Dashboard
            </button>
          </div>
        </div>
      </Card>
    );
  }

  // --- ACTIVE SESSION UI ---
  return (
    <div className="max-w-3xl mx-auto">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">{assessment.title}</h2>
          <p className="text-gray-500">Question {currentQuestionIndex + 1} of {assessment.questions.length}</p>
        </div>
        <button onClick={onCancel} className="text-gray-400 hover:text-red-500">
          <i className="fa-solid fa-xmark text-2xl"></i>
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-md border border-gray-100 overflow-hidden">
        <div className="w-full h-2 bg-gray-100">
          <div 
            className="h-full bg-indigo-600 transition-all duration-300"
            style={{ width: `${((currentQuestionIndex + 1) / assessment.questions.length) * 100}%` }}
          />
        </div>

        <div className="p-8">
          <p className="text-xl text-gray-800 font-medium mb-6">{currentQuestion.text}</p>

          {currentQuestion.imageUrl && (
            <div className="mb-8 p-4 bg-white border border-gray-100 rounded-xl shadow-sm flex justify-center">
              <img 
                src={currentQuestion.imageUrl} 
                alt="Question Diagram" 
                className="max-h-48 object-contain rounded"
              />
            </div>
          )}

          <div className="space-y-4">
            {currentQuestion.options.map((option) => (
              <button
                key={option.id}
                disabled={isRevealed}
                onClick={() => handleSelectOption(option.id)}
                className={`w-full text-left p-4 rounded-xl border-2 transition-all flex items-center gap-4 ${getOptionStyles(currentQuestion, option.id)}`}
              >
                <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center ${
                  responses[currentQuestion.id] === option.id ? (isRevealed && currentQuestion.correctOptionId !== option.id ? 'border-red-500 bg-red-500' : 'border-indigo-600 bg-indigo-600') : 
                  (isRevealed && currentQuestion.correctOptionId === option.id ? 'border-green-500 bg-green-500' : 'border-gray-300')
                }`}>
                  {(responses[currentQuestion.id] === option.id || (isRevealed && currentQuestion.correctOptionId === option.id)) && <div className="w-2 h-2 bg-white rounded-full" />}
                </div>
                <span className="text-lg">{option.text}</span>
              </button>
            ))}
          </div>

          {isRevealed && currentQuestion.explanation && (
            <div className="mt-8 p-4 bg-indigo-50 border-l-4 border-indigo-400 rounded animate-in fade-in slide-in-from-top-2 duration-300">
              <p className="text-sm font-bold text-indigo-700 uppercase mb-1">Explanation</p>
              <p className="text-indigo-900">{currentQuestion.explanation}</p>
            </div>
          )}
        </div>

        <div className="p-6 bg-gray-50 border-t border-gray-100 flex items-center justify-between">
          <button
            disabled={currentQuestionIndex === 0}
            onClick={() => {
              setCurrentQuestionIndex(prev => prev - 1);
            }}
            className="px-4 py-2 font-semibold text-gray-600 hover:text-indigo-600 disabled:opacity-30"
          >
            <i className="fa-solid fa-arrow-left mr-2"></i> Previous
          </button>

          <div className="flex items-center gap-4">
            {isPractice && !isRevealed && (
              <button
                disabled={!hasSelected}
                onClick={handleShowAnswer}
                className="px-4 py-2 text-indigo-600 font-bold hover:bg-indigo-100 rounded-lg disabled:opacity-30 transition-colors flex items-center gap-2"
              >
                <i className="fa-solid fa-eye"></i> Show Answer
              </button>
            )}

            {isLastQuestion ? (
              <button
                disabled={!hasSelected}
                onClick={handleSubmit}
                className="px-8 py-3 bg-green-600 hover:bg-green-700 text-white rounded-lg font-bold shadow-lg shadow-green-200 transition-transform active:scale-95 disabled:opacity-50"
              >
                Finish & Submit
              </button>
            ) : (
              <button
                disabled={!hasSelected}
                onClick={() => {
                  setCurrentQuestionIndex(prev => prev + 1);
                }}
                className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-bold shadow-lg shadow-indigo-200 transition-transform active:scale-95 disabled:opacity-50"
              >
                Next <i className="fa-solid fa-arrow-right ml-2"></i>
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Assessment, Submission, Question } from '../../types';
import { Card } from '../UI/Card';
import { GoogleGenAI } from "@google/genai";

interface SubmissionReviewProps {
  submission: Submission;
  assessment: Assessment;
  onClose: () => void;
}

export const SubmissionReview: React.FC<SubmissionReviewProps> = ({ submission, assessment, onClose }) => {
  const [aiExplanations, setAiExplanations] = useState<Record<string, string>>({});
  const [aiLoadingIds, setAiLoadingIds] = useState<Record<string, boolean>>({});

  const handleAskGemini = async (question: Question) => {
    setAiLoadingIds(prev => ({ ...prev, [question.id]: true }));
    try {
      // Create a new instance right before the call to ensure up-to-date API key
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const userSelected = question.options.find(o => o.id === submission.responses[question.id])?.text || "None";
      const correctText = question.options.find(o => o.id === question.correctOptionId)?.text;

      const prompt = `You are an expert tutor for Panday Classes. 
      The student is reviewing their attempt for the question: "${question.text}"
      The correct answer is: "${correctText}".
      The student chose: "${userSelected}".
      Provide a logical, clear, and encouraging explanation (max 100 words) focusing on the conceptual reason why "${correctText}" is the right choice.`;

      // Use generateContent with both model name and prompt
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: { 
          // Guidelines: Always set maxOutputTokens and thinkingBudget together
          maxOutputTokens: 4096,
          thinkingConfig: { thinkingBudget: 1500 } 
        }
      });

      // Access the .text property directly (not a method)
      setAiExplanations(prev => ({ ...prev, [question.id]: response.text || "No explanation available." }));
    } catch (err) {
      console.error("Gemini AI Error:", err);
      setAiExplanations(prev => ({ ...prev, [question.id]: "Unable to connect to AI tutor. Please try again." }));
    } finally {
      setAiLoadingIds(prev => ({ ...prev, [question.id]: false }));
    }
  };

  const percentage = (submission.score / submission.totalQuestions) * 100;

  return (
    <div className="max-w-4xl mx-auto py-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <div>
          <button 
            onClick={onClose}
            className="flex items-center gap-2 text-indigo-600 font-bold mb-4 hover:translate-x-[-4px] transition-transform"
          >
            <i className="fa-solid fa-arrow-left"></i> Back to Performance Analytics
          </button>
          <h2 className="text-3xl font-black text-gray-900">Review: {assessment.title}</h2>
          <p className="text-gray-500 font-medium">Completed on {new Date(submission.completedAt).toLocaleDateString()}</p>
        </div>
        <Card className="!bg-indigo-600 text-white !p-4 flex items-center gap-6 shadow-lg shadow-indigo-100">
           <div className="text-center">
              <p className="text-[10px] font-black uppercase tracking-widest opacity-80">Final Score</p>
              <p className="text-3xl font-black">{submission.score} / {submission.totalQuestions}</p>
           </div>
           <div className="w-px h-10 bg-white/20"></div>
           <div className="text-center">
              <p className="text-[10px] font-black uppercase tracking-widest opacity-80">Accuracy</p>
              <p className="text-3xl font-black">{Math.round(percentage)}%</p>
           </div>
        </Card>
      </div>

      <div className="space-y-8">
        {assessment.questions.map((q, idx) => {
          const userSelectedId = submission.responses[q.id];
          const isCorrect = userSelectedId === q.correctOptionId;
          const aiExplanation = aiExplanations[q.id];
          const isAiLoading = aiLoadingIds[q.id];

          return (
            <Card key={q.id} className={`overflow-hidden border-2 ${isCorrect ? 'border-emerald-100' : 'border-red-100'}`}>
              <div className="flex items-start justify-between mb-6">
                <div className="flex items-center gap-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black ${isCorrect ? 'bg-emerald-100 text-emerald-600' : 'bg-red-100 text-red-600'}`}>
                    {idx + 1}
                  </div>
                  <div>
                    <h4 className="text-lg font-bold text-gray-800 leading-tight">{q.text}</h4>
                    <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded mt-2 inline-block ${isCorrect ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                      {isCorrect ? 'Correct' : 'Incorrect'}
                    </span>
                  </div>
                </div>
                {!isCorrect && !aiExplanation && !isAiLoading && (
                  <button 
                    onClick={() => handleAskGemini(q)}
                    className="flex items-center gap-2 bg-violet-600 text-white px-4 py-2 rounded-xl text-xs font-black uppercase hover:bg-violet-700 transition-all shadow-md shadow-violet-100 active:scale-95"
                  >
                    <i className="fa-solid fa-sparkles"></i> Ask AI Tutor
                  </button>
                )}
              </div>

              {q.imageUrl && (
                <div className="mb-6 p-4 bg-white border border-gray-100 rounded-xl shadow-sm flex justify-center">
                  <img src={q.imageUrl} alt="Question Diagram" className="max-h-40 object-contain" />
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                {q.options.map((opt) => {
                  const isOptSelected = userSelectedId === opt.id;
                  const isOptCorrect = q.correctOptionId === opt.id;

                  let style = "border-gray-100 bg-gray-50 text-gray-500";
                  let icon = null;

                  if (isOptCorrect) {
                    style = "border-emerald-500 bg-emerald-50 text-emerald-800 font-bold ring-2 ring-emerald-500/20";
                    icon = <i className="fa-solid fa-circle-check text-emerald-500 ml-auto"></i>;
                  } else if (isOptSelected && !isOptCorrect) {
                    style = "border-red-500 bg-red-50 text-red-800 font-bold ring-2 ring-red-500/20";
                    icon = <i className="fa-solid fa-circle-xmark text-red-500 ml-auto"></i>;
                  }

                  return (
                    <div key={opt.id} className={`p-4 rounded-xl border-2 flex items-center gap-3 transition-all ${style}`}>
                      <span className="text-sm">{opt.text}</span>
                      {icon}
                    </div>
                  );
                })}
              </div>

              {(q.explanation || aiExplanation || isAiLoading) && (
                <div className="mt-4 p-5 bg-gray-50 rounded-2xl border border-gray-100 space-y-4">
                  {q.explanation && (
                    <div>
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Standard Explanation</p>
                      <p className="text-sm text-gray-700 leading-relaxed">{q.explanation}</p>
                    </div>
                  )}

                  {isAiLoading ? (
                    <div className="flex items-center gap-3 text-violet-600 animate-pulse py-2">
                      <i className="fa-solid fa-circle-notch animate-spin"></i>
                      <span className="text-sm font-black uppercase tracking-wider">Gemini AI Tutor is thinking...</span>
                    </div>
                  ) : aiExplanation ? (
                    <div className="border-t border-gray-200 pt-4 animate-in fade-in slide-in-from-top-2 duration-300">
                      <div className="flex items-center gap-2 mb-2">
                        <i className="fa-solid fa-sparkles text-violet-500"></i>
                        <p className="text-[10px] font-black text-violet-600 uppercase tracking-widest">AI Tutor Insights</p>
                      </div>
                      <p className="text-sm text-gray-800 italic leading-relaxed">"{aiExplanation}"</p>
                    </div>
                  ) : null}
                </div>
              )}
            </Card>
          );
        })}
      </div>

      <div className="mt-12 flex justify-center">
        <button 
          onClick={onClose}
          className="px-10 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 hover:translate-y-[-2px] transition-all active:scale-95"
        >
          Return to Dashboard
        </button>
      </div>
    </div>
  );
};

