import { 
  collection, 
  doc, 
  getDoc, 
  getDocs, 
  setDoc, 
  addDoc, 
  query, 
  where
} from "firebase/firestore";
import { db } from "../lib/firebase";
import { Submission, Assessment, User } from '../types';
import { INITIAL_ASSESSMENTS, MOCK_TEACHER, MOCK_STUDENTS } from '../constants';

const COLLECTIONS = {
  USERS: 'users',
  SUBMISSIONS: 'submissions',
  ASSESSMENTS: 'assessments'
};

const USER_SESSION_KEY = 'panday_user_id';

export const storageService = {
  getCurrentUserLocal: (): string | null => {
    return localStorage.getItem(USER_SESSION_KEY);
  },

  setCurrentUserLocal: (userId: string | null) => {
    if (userId) localStorage.setItem(USER_SESSION_KEY, userId);
    else localStorage.removeItem(USER_SESSION_KEY);
  },

  getUserById: async (userId: string): Promise<User | null> => {
    try {
      const docRef = doc(db, COLLECTIONS.USERS, userId);
      const docSnap = await getDoc(docRef);
      return docSnap.exists() ? (docSnap.data() as User) : null;
    } catch (e) {
      console.error("Firebase getUserById error:", e);
      return null;
    }
  },

  getAllStudents: async (): Promise<User[]> => {
    try {
      const q = query(collection(db, COLLECTIONS.USERS), where("role", "==", "STUDENT"));
      const querySnapshot = await getDocs(q);
      return querySnapshot.docs.map(doc => doc.data() as User);
    } catch (e) {
      console.error("Error getting students:", e);
      return [];
    }
  },

  registerStudent: async (student: User): Promise<void> => {
    await setDoc(doc(db, COLLECTIONS.USERS, student.id), student);
  },

  findUserByCredentials: async (username: string, role: string): Promise<User | null> => {
    try {
      const qUsername = query(
        collection(db, COLLECTIONS.USERS), 
        where("username", "==", username),
        where("role", "==", role)
      );
      const snapUsername = await getDocs(qUsername);
      if (!snapUsername.empty) return snapUsername.docs[0].data() as User;

      const qEmail = query(
        collection(db, COLLECTIONS.USERS), 
        where("email", "==", username),
        where("role", "==", role)
      );
      const snapEmail = await getDocs(qEmail);
      if (!snapEmail.empty) return snapEmail.docs[0].data() as User;
    } catch (e) {
      console.error("Auth query error:", e);
    }
    return null;
  },

  getSubmissions: async (studentId?: string): Promise<Submission[]> => {
    try {
      const submissionsRef = collection(db, COLLECTIONS.SUBMISSIONS);
      const q = studentId 
        ? query(submissionsRef, where("studentId", "==", studentId))
        : query(submissionsRef);
      const querySnapshot = await getDocs(q);
      return querySnapshot.docs.map(doc => doc.data() as Submission);
    } catch (e) {
      console.error("Error fetching submissions:", e);
      return [];
    }
  },

  saveSubmission: async (submission: Submission): Promise<void> => {
    await addDoc(collection(db, COLLECTIONS.SUBMISSIONS), submission);
  },

  saveAssessment: async (assessment: Assessment): Promise<void> => {
    await setDoc(doc(db, COLLECTIONS.ASSESSMENTS, assessment.id), assessment);
  },

  getAssessments: async (): Promise<Assessment[]> => {
    try {
      const querySnapshot = await getDocs(collection(db, COLLECTIONS.ASSESSMENTS));
      const cloudAssessments = querySnapshot.docs.map(doc => doc.data() as Assessment);

      // If cloud is empty, seed with initials
      if (cloudAssessments.length === 0) {
        for (const assessment of INITIAL_ASSESSMENTS) {
          await setDoc(doc(db, COLLECTIONS.ASSESSMENTS, assessment.id), assessment);
        }
        return INITIAL_ASSESSMENTS;
      }
      return cloudAssessments;
    } catch (e) {
      console.error("Error fetching assessments:", e);
      return INITIAL_ASSESSMENTS;
    }
  },

  seedInitialData: async (): Promise<void> => {
    try {
      const teacherDoc = doc(db, COLLECTIONS.USERS, MOCK_TEACHER.id);
      await setDoc(teacherDoc, MOCK_TEACHER, { merge: true });
      for (const student of MOCK_STUDENTS) {
        await setDoc(doc(db, COLLECTIONS.USERS, student.id), student, { merge: true });
      }
    } catch (e) {
      console.error("Seeding initial data failed:", e);
    }
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Assessment, User, Submission, AssessmentType, Subject, Question, Type } from '../../types';
import { Card } from '../UI/Card';
import { storageService } from '../../services/storageService';
import { GoogleGenAI } from "@google/genai";

interface TeacherDashboardProps {
  user: User;
  assessments: Assessment[];
}

export const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ assessments: initialAssessments }) => {
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [students, setStudents] = useState<User[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'ANALYTICS' | 'AI_CREATOR'>('ANALYTICS');

  // AI Creator States
  const [pdfFile, setPdfFile] = useState<File | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedPreview, setGeneratedPreview] = useState<Partial<Assessment> | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true);
        const [allSubmissions, allStudents] = await Promise.all([
          storageService.getSubmissions(),
          storageService.getAllStudents()
        ]);
        setSubmissions(allSubmissions);
        setStudents(allStudents);
      } catch (err) {
        console.error("Error loading teacher data:", err);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      setPdfFile(file);
    } else {
      alert("Please upload a valid PDF file.");
    }
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = error => reject(error);
    });
  };

  const generateAssessment = async () => {
    if (!pdfFile) return;
    setIsGenerating(true);
    try {
      const base64Data = await fileToBase64(pdfFile);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const prompt = `Analyze this PDF document and extract at least 5 multiple-choice questions. 
      Generate a comprehensive assessment based on the content.
      Include clear explanations for each correct answer.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [
          {
            inlineData: {
              data: base64Data,
              mimeType: 'application/pdf'
            }
          },
          { text: prompt }
        ],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: "OBJECT" as any,
            properties: {
              title: { type: "STRING" as any },
              subject: { type: "STRING" as any, enum: ["Mathematics", "Physics", "Chemistry"] },
              questions: {
                type: "ARRAY" as any,
                items: {
                  type: "OBJECT" as any,
                  properties: {
                    text: { type: "STRING" as any },
                    options: {
                      type: "ARRAY" as any,
                      items: {
                        type: "OBJECT" as any,
                        properties: {
                          id: { type: "STRING" as any },
                          text: { type: "STRING" as any }
                        }
                      }
                    },
                    correctOptionId: { type: "STRING" as any },
                    explanation: { type: "STRING" as any }
                  }
                }
              }
            }
          }
        }
      });

      const result = JSON.parse(response.text || "{}");
      setGeneratedPreview({
        ...result,
        type: 'PRACTICE',
        id: `ai_${Math.random().toString(36).substr(2, 9)}`
      });
    } catch (err) {
      console.error("AI Generation Error:", err);
      alert("Failed to generate questions. Ensure your PDF has clear text content.");
    } finally {
      setIsGenerating(false);
    }
  };

  const saveToCloud = async () => {
    if (!generatedPreview) return;
    try {
      await storageService.saveAssessment(generatedPreview as Assessment);
      alert("Assessment successfully saved to cloud!");
      setGeneratedPreview(null);
      setPdfFile(null);
      setActiveTab('ANALYTICS');
    } catch (err) {
      console.error("Save Error:", err);
    }
  };

  const getStudentSubmissions = (studentId: string) => {
    return submissions.filter(s => s.studentId === studentId);
  };

  const getAverageScore = (studentId: string) => {
    const subs = getStudentSubmissions(studentId);
    if (subs.length === 0) return 0;
    const total = subs.reduce((acc, curr) => acc + (curr.score / curr.totalQuestions), 0);
    return (total / subs.length) * 100;
  };

  if (loading) {
    return (
      <div className="max-w-7xl mx-auto py-20 px-4 text-center">
        <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
        <p className="text-gray-500 font-bold">Synchronizing Faculty Data...</p>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto py-10 px-4">
      <header className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <div>
          <h1 className="text-4xl font-extrabold text-gray-900 mb-1">Faculty Portal</h1>
          <p className="text-lg text-gray-600">Managing Panday Classes Excellence.</p>
        </div>

        <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-gray-100">
          <button 
            onClick={() => setActiveTab('ANALYTICS')}
            className={`px-6 py-2 rounded-xl font-bold text-sm transition-all ${activeTab === 'ANALYTICS' ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-500 hover:text-indigo-600'}`}
          >
            Analytics
          </button>
          <button 
            onClick={() => setActiveTab('AI_CREATOR')}
            className={`px-6 py-2 rounded-xl font-bold text-sm transition-all ${activeTab === 'AI_CREATOR' ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-500 hover:text-indigo-600'}`}
          >
            AI Assessment Creator
          </button>
        </div>
      </header>

      {activeTab === 'ANALYTICS' ? (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Student List */}
          <div className="lg:col-span-1">
            <Card title="Students Directory" icon="fa-user-graduate">
              <div className="space-y-2">
                {students.map(student => {
                  const avg = getAverageScore(student.id);
                  const isActive = selectedStudent?.id === student.id;
                  return (
                    <button
                      key={student.id}
                      onClick={() => setSelectedStudent(student)}
                      className={`w-full text-left p-4 rounded-xl transition-all border flex items-center gap-3 ${
                        isActive 
                          ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' 
                          : 'bg-gray-50 border-gray-100 text-gray-700 hover:bg-gray-100'
                      }`}
                    >
                      <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold ${isActive ? 'bg-white text-indigo-600' : 'bg-indigo-100 text-indigo-700'}`}>
                        {student.name.charAt(0)}
                      </div>
                      <div className="flex-grow">
                        <p className="font-bold">{student.name}</p>
                        <p className={`text-xs ${isActive ? 'text-indigo-100' : 'text-gray-500'}`}>
                          {getStudentSubmissions(student.id).length} assessments completed
                        </p>
                      </div>
                      {avg > 0 && (
                        <div className={`text-xs font-black rounded px-2 py-1 ${isActive ? 'bg-indigo-500' : 'bg-white border'}`}>
                          {Math.round(avg)}%
                        </div>
                      )}
                    </button>
                  );
                })}
              </div>
            </Card>
          </div>

          {/* Student Detail */}
          <div className="lg:col-span-2">
            {selectedStudent ? (
              <div className="space-y-6">
                <Card title={`${selectedStudent.name}'s Progress`} icon="fa-chart-column">
                  <div className="overflow-x-auto">
                    <table className="w-full text-left">
                      <thead>
                        <tr className="border-b border-gray-100">
                          <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Date</th>
                          <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Assessment</th>
                          <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Score</th>
                          <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Accuracy</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-50">
                        {getStudentSubmissions(selectedStudent.id).slice().reverse().map((sub, sidx) => {
                          const accuracy = (sub.score / sub.totalQuestions) * 100;
                          return (
                            <tr key={sidx}>
                              <td className="py-4 text-sm text-gray-500">
                                {new Date(sub.completedAt).toLocaleDateString()}
                              </td>
                              <td className="py-4">
                                <span className="font-semibold text-gray-800">{sub.assessmentId}</span>
                              </td>
                              <td className="py-4">
                                <span className="font-bold text-gray-700">{sub.score} / {sub.totalQuestions}</span>
