                      <>
                        <i className="fa-solid fa-bolt"></i>
                        Generate Assessment
                      </>
                    )}
                  </button>
                </div>
              </div>
            ) : (
              <div className="space-y-6">
                <div className="flex items-center justify-between p-4 bg-indigo-50 rounded-2xl border border-indigo-100">
                  <div>
                    <h4 className="font-black text-indigo-900">{generatedPreview.title}</h4>
                    <p className="text-xs font-bold text-indigo-600 uppercase tracking-widest">{generatedPreview.subject} • {generatedPreview.questions?.length} Questions Generated</p>
                  </div>
                  <button 
                    onClick={() => setGeneratedPreview(null)}
                    className="text-gray-400 hover:text-red-500 font-bold text-xs"
                  >
                    Discard & Retry
                  </button>
                </div>

                <div className="space-y-4 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                  {generatedPreview.questions?.map((q, qidx) => (
                    <div key={qidx} className="p-6 bg-gray-50 rounded-2xl border border-gray-100">
                      <p className="font-bold text-gray-800 mb-4">{q.text}</p>
                      <div className="grid grid-cols-2 gap-2">
                        {q.options.map((opt) => (
                          <div key={opt.id} className={`p-3 rounded-lg text-xs font-medium border ${opt.id === q.correctOptionId ? 'bg-emerald-50 border-emerald-200 text-emerald-700' : 'bg-white border-gray-100 text-gray-500'}`}>
