import React, { useState, useEffect, useRef } from 'react';
import { Assessment, User, Submission, AssessmentType, Subject, Question } from '../../types';
import { Card } from '../UI/Card';
import { storageService } from '../../services/storageService';
import { GoogleGenAI, Type } from "@google/genai";

interface TeacherDashboardProps {
  user: User;
  assessments: Assessment[];
}

export const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ assessments: initialAssessments }) => {
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [students, setStudents] = useState<User[]>([]);
  const [selectedStudent, setSelectedStudent] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<'ANALYTICS' | 'AI_CREATOR'>('ANALYTICS');

  // AI Creator States
  const [pdfFile, setPdfFile] = useState<File | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedPreview, setGeneratedPreview] = useState<Partial<Assessment> | null>(null);
  const [targetType, setTargetType] = useState<AssessmentType>('PRACTICE');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true);
        const [allSubmissions, allStudents] = await Promise.all([
          storageService.getSubmissions(),
          storageService.getAllStudents()
        ]);
        setSubmissions(allSubmissions);
        setStudents(allStudents);
      } catch (err) {
        console.error("Error loading teacher data:", err);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      setPdfFile(file);
    } else {
      alert("Please upload a valid PDF file.");
    }
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = error => reject(error);
    });
  };

  const generateAssessment = async () => {
    if (!pdfFile) return;
    setIsGenerating(true);
    try {
      const base64Data = await fileToBase64(pdfFile);
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const prompt = `Task: Create an educational ${targetType.toLowerCase()} set from the provided PDF.
      Requirements:
      1. Extract exactly 5 high-quality multiple-choice questions.
      2. Each question must have 4 options with IDs 'a', 'b', 'c', and 'd'.
      3. Focus on conceptual understanding and core facts.
      4. Explanations must be concise (max 2 sentences).
      5. Output ONLY the raw JSON object matching the schema. Do not include markdown formatting or extra text.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [
          {
            inlineData: {
              data: base64Data,
              mimeType: 'application/pdf'
            }
          },
          { text: prompt }
        ],
        config: {
          responseMimeType: "application/json",
          // Set higher token limit and thinking budget to avoid truncated JSON
          maxOutputTokens: 8192,
          thinkingConfig: { thinkingBudget: 4000 },
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              subject: { type: Type.STRING, description: "Mathematics, Physics, or Chemistry" },
              questions: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    text: { type: Type.STRING },
                    options: {
                      type: Type.ARRAY,
                      items: {
                        type: Type.OBJECT,
                        properties: {
                          id: { type: Type.STRING },
                          text: { type: Type.STRING }
                        },
                        required: ["id", "text"]
                      }
                    },
                    correctOptionId: { type: Type.STRING },
                    explanation: { type: Type.STRING }
                  },
                  required: ["text", "options", "correctOptionId"]
                }
              }
            },
            required: ["title", "subject", "questions"]
          }
        }
      });

      let rawText = response.text || "";
      // Strip potential markdown wrappers that can occasionally appear even with JSON mode
      rawText = rawText.replace(/^```json\n?/, "").replace(/\n?```$/, "").trim();

      if (!rawText) throw new Error("Empty response from AI");

      const result = JSON.parse(rawText);
      setGeneratedPreview({
        ...result,
        type: targetType,
        id: `ai_${Math.random().toString(36).substr(2, 9)}`,
        durationMinutes: targetType === 'TEST' ? 30 : undefined
      });
    } catch (err: any) {
      console.error("AI Generation Error:", err);
      let errorMsg = "Failed to generate questions. ";
      if (err.message.includes("Unterminated string") || err.message.includes("Unexpected end")) {
        errorMsg += "The AI response was cut off. Try a smaller PDF or different content.";
      } else {
        errorMsg += "Ensure your PDF has clear text content.";
      }
      alert(errorMsg);
    } finally {
      setIsGenerating(false);
    }
  };

  const saveToCloud = async () => {
    if (!generatedPreview) return;
    try {
      await storageService.saveAssessment(generatedPreview as Assessment);
      alert("Assessment successfully saved to cloud!");
      setGeneratedPreview(null);
      setPdfFile(null);
      setActiveTab('ANALYTICS');
    } catch (err) {
      console.error("Save Error:", err);
    }
  };

  const getStudentSubmissions = (studentId: string) => {
    return submissions.filter(s => s.studentId === studentId);
  };

  const getAverageScore = (studentId: string) => {
    const subs = getStudentSubmissions(studentId);
    if (subs.length === 0) return 0;
    const total = subs.reduce((acc, curr) => acc + (curr.score / curr.totalQuestions), 0);
    return (total / subs.length) * 100;
  };

  if (loading) {
    return (
      <div className="max-w-7xl mx-auto py-20 px-4 text-center">
        <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
        <p className="text-gray-500 font-bold">Synchronizing Faculty Data...</p>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto py-10 px-4">
      <header className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <div>
          <h1 className="text-4xl font-extrabold text-gray-900 mb-1">Faculty Portal</h1>
          <p className="text-lg text-gray-600">Managing Panday Classes Excellence.</p>
        </div>

        <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-gray-100">
          <button 
            onClick={() => setActiveTab('ANALYTICS')}
            className={`px-6 py-2 rounded-xl font-bold text-sm transition-all ${activeTab === 'ANALYTICS' ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-500 hover:text-indigo-600'}`}
          >
            Analytics
          </button>
          <button 
            onClick={() => setActiveTab('AI_CREATOR')}
            className={`px-6 py-2 rounded-xl font-bold text-sm transition-all ${activeTab === 'AI_CREATOR' ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-500 hover:text-indigo-600'}`}
          >
            AI Assessment Creator
          </button>
        </div>
      </header>

      {activeTab === 'ANALYTICS' ? (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Student List */}
          <div className="lg:col-span-1">
            <Card title="Students Directory" icon="fa-user-graduate">
              <div className="space-y-2">
                {students.map(student => {
                  const avg = getAverageScore(student.id);
                  const isActive = selectedStudent?.id === student.id;
                  return (
                    <button
                      key={student.id}
                      onClick={() => setSelectedStudent(student)}
                      className={`w-full text-left p-4 rounded-xl transition-all border flex items-center gap-3 ${
                        isActive 
                          ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' 
                          : 'bg-gray-50 border-gray-100 text-gray-700 hover:bg-gray-100'
                      }`}
                    >
                      <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold ${isActive ? 'bg-white text-indigo-600' : 'bg-indigo-100 text-indigo-700'}`}>
                        {student.name.charAt(0)}
                      </div>
                      <div className="flex-grow">
                        <p className="font-bold">{student.name}</p>
                        <p className={`text-xs ${isActive ? 'text-indigo-100' : 'text-gray-500'}`}>
                          {getStudentSubmissions(student.id).length} assessments completed
                        </p>
                      </div>
                      {avg > 0 && (
                        <div className={`text-xs font-black rounded px-2 py-1 ${isActive ? 'bg-indigo-500' : 'bg-white border'}`}>
                          {Math.round(avg)}%
                        </div>
                      )}
                    </button>
                  );
                })}
              </div>
            </Card>
          </div>

          {/* Student Detail */}
          <div className="lg:col-span-2">
            {selectedStudent ? (
              <div className="space-y-6">
                <Card title={`${selectedStudent.name}'s Progress`} icon="fa-chart-column">
                  <div className="overflow-x-auto">
                    <table className="w-full text-left">
                      <thead>
                        <tr className="border-b border-gray-100">
                          <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Date</th>
                          <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Assessment</th>
                          <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Score</th>
                          <th className="py-3 font-semibold text-gray-600 uppercase text-xs">Accuracy</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-50">
                        {getStudentSubmissions(selectedStudent.id).slice().reverse().map((sub, sidx) => {
                          const accuracy = (sub.score / sub.totalQuestions) * 100;
                          return (
                            <tr key={sidx}>
                              <td className="py-4 text-sm text-gray-500">
                                {new Date(sub.completedAt).toLocaleDateString()}
                              </td>
                              <td className="py-4">
                                <span className="font-semibold text-gray-800">{sub.assessmentId}</span>
                              </td>
                              <td className="py-4">
                                <span className="font-bold text-gray-700">{sub.score} / {sub.totalQuestions}</span>
                              </td>
                              <td className="py-4">
                                <span className={`text-xs font-black ${accuracy >= 80 ? 'text-emerald-600' : 'text-orange-500'}`}>
                                  {Math.round(accuracy)}%
                                </span>
                              </td>
                            </tr>
                          );
                        })}
                      </tbody>
                    </table>
                  </div>
                </Card>
              </div>
            ) : (
              <div className="h-full min-h-[400px] flex flex-col items-center justify-center bg-gray-50 border-2 border-dashed border-gray-200 rounded-3xl p-10 text-center">
                <i className="fa-solid fa-users-viewfinder text-gray-300 text-6xl mb-4"></i>
                <h3 className="text-xl font-bold text-gray-400">Select a student to analyze cloud records.</h3>
              </div>
            )}
          </div>
        </div>
      ) : (
        <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4">
          <Card title="PDF to Assessment AI" icon="fa-wand-magic-sparkles">
            {!generatedPreview ? (
              <div className="py-10">
                {/* Mode Selector */}
                <div className="flex justify-center mb-8 gap-4">
                  <button 
                    onClick={() => setTargetType('PRACTICE')}
                    className={`px-8 py-3 rounded-2xl font-black uppercase tracking-widest text-xs border-2 transition-all ${targetType === 'PRACTICE' ? 'bg-emerald-50 border-emerald-600 text-emerald-700 shadow-lg shadow-emerald-50' : 'bg-white border-gray-100 text-gray-400 hover:border-emerald-200'}`}
                  >
                    Practice Set
                  </button>
                  <button 
                    onClick={() => setTargetType('TEST')}
                    className={`px-8 py-3 rounded-2xl font-black uppercase tracking-widest text-xs border-2 transition-all ${targetType === 'TEST' ? 'bg-indigo-50 border-indigo-600 text-indigo-700 shadow-lg shadow-indigo-50' : 'bg-white border-gray-100 text-gray-400 hover:border-indigo-200'}`}
                  >
                    Test Set (Timed)
                  </button>
                </div>

                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className={`border-4 border-dashed rounded-3xl p-16 text-center transition-all cursor-pointer ${pdfFile ? 'border-emerald-200 bg-emerald-50' : 'border-gray-100 bg-gray-50 hover:border-indigo-200 hover:bg-indigo-50'}`}
                >
                  <input 
                    type="file" 
                    className="hidden" 
                    ref={fileInputRef} 
                    accept=".pdf" 
                    onChange={handleFileUpload}
                  />
                  <i className={`fa-solid ${pdfFile ? 'fa-file-circle-check text-emerald-500' : 'fa-cloud-arrow-up text-gray-300'} text-6xl mb-6`}></i>
                  {pdfFile ? (
