                  ) : (
                    <div>
                      <p className="text-xl font-bold text-gray-700 mb-1">Upload study material PDF</p>
                      <p className="text-gray-400 text-sm">Gemini will extract and format questions automatically.</p>
                    </div>
                  )}
                </div>

                <div className="mt-8 flex justify-center">
                  <button
                    disabled={!pdfFile || isGenerating}
                    onClick={generateAssessment}
                    className="px-12 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl shadow-indigo-100 hover:bg-indigo-700 disabled:opacity-50 transition-all flex items-center gap-3"
                  >
                    {isGenerating ? (
                      <>
                        <i className="fa-solid fa-circle-notch animate-spin"></i>
                        AI is Analyzing PDF...
                      </>
                    ) : (
                      <>
