                    <h4 className="font-black text-indigo-900">{generatedPreview.title}</h4>
                    <p className="text-xs font-bold text-indigo-600 uppercase tracking-widest">{generatedPreview.subject} • {generatedPreview.questions?.length} Questions • {targetType}</p>
